const UNIT_23 =
{n:23,lang:"ko",srcLang:"en",track:"v2",title:"뉴스 읽기",sub:"News & Reported Speech",icon:"📰",level:"B2.1",color:"#5B8DEF",lessons:[

// ── L1: 뉴스를 읽어요 (Reading News — Vocabulary) ──
{id:"kou23l1",title:"뉴스를 읽어요",icon:"📰",xp:20,board:true,steps:[
{type:"intro",title:"Reading Korean News",desc:"뉴스를 읽어요\n→ News vocabulary for reading Korean media.\n\nKorean news uses a different register from speech.\nThis unit teaches you to READ and UNDERSTAND news,\nthen REPORT what you learned to others.",goals:["Learn core news vocabulary","Understand news article structure","Distinguish news register from spoken Korean"]},
{type:"teach",kind:"noun",nl:"기사",en:"news article",pos:"noun",gender:null,funFact:"Sino-Korean compound: 기(record/記) + 사(matter/事)",phonetic:"gi-sa",example:"이 기사를 읽어 보세요.\n(Please read this article.)",exampleEn:"Please read this article.",note:"COMPOUND: 기(record/記) + 사(matter/事).\nRecord-matter: a written account of events.\n기자 = journalist (기 + 자 person)."},
{type:"teach",kind:"noun",nl:"보도",en:"news report / coverage",pos:"noun",gender:null,funFact:"Sino-Korean compound: 보(report/報) + 도(guide/導)",phonetic:"bo-do",example:"보도에 따르면 사고가 발생했습니다.\n(According to the report, an accident occurred.)",exampleEn:"According to the report, an accident occurred.",note:"COMPOUND: 보(report/報) + 도(guide/導).\nReport-guide: formally conveying news.\n보도하다 = to report (news)."},
{type:"teach",kind:"noun",nl:"사건",en:"incident / case",pos:"noun",gender:null,funFact:"Sino-Korean compound: 사(matter/事) + 건(matter/件)",phonetic:"sa-geon",example:"이 사건은 큰 관심을 받았습니다.\n(This incident received great attention.)",exampleEn:"This incident received great attention.",note:"COMPOUND: 사(matter/事) + 건(matter/件).\nDouble-matter: emphasizes the event.\n사건 사고 = incidents and accidents."},
{type:"teach",kind:"noun",nl:"사고",en:"accident",pos:"noun",gender:null,funFact:"Sino-Korean compound: 사(matter/事) + 고(cause/故)",phonetic:"sa-go",example:"교통사고로 인해 길이 막혔습니다.\n(The road was blocked due to a traffic accident.)",exampleEn:"The road was blocked due to a traffic accident.",note:"COMPOUND: 사(matter/事) + 고(cause/故).\nMatter-cause: an unexpected event.\n교통사고 = traffic accident."},
{type:"teach",kind:"noun",nl:"발표",en:"announcement / presentation",pos:"noun",gender:null,funFact:"Sino-Korean compound: 발(send/發) + 표(show/表)",phonetic:"bal-pyo",example:"정부가 새 정책을 발표했습니다.\n(The government announced a new policy.)",exampleEn:"The government announced a new policy.",note:"COMPOUND: 발(send/發) + 표(show/表).\nSend-show: making something publicly known.\n발표하다 = to announce."},
{type:"teach",kind:"noun",nl:"조사",en:"investigation / survey",pos:"noun",gender:null,funFact:"Sino-Korean compound: 조(investigate/調) + 사(examine/査)",phonetic:"jo-sa",example:"경찰이 사건을 조사하고 있습니다.\n(Police are investigating the incident.)",exampleEn:"Police are investigating the incident.",note:"COMPOUND: 조(investigate/調) + 사(examine/査).\nInvestigate-examine: systematic inquiry.\n여론 조사 = opinion poll."},
{type:"teach",kind:"noun",nl:"통계",en:"statistics",pos:"noun",gender:null,funFact:"Sino-Korean compound: 통(total/統) + 계(count/計)",phonetic:"tong-gye",example:"통계에 의하면 인구가 줄고 있습니다.\n(According to statistics, the population is decreasing.)",exampleEn:"According to statistics, the population is decreasing.",note:"COMPOUND: 통(total/統) + 계(count/計).\nTotal-count: numerical data.\n통계청 = Statistics Korea (government agency)."},
{type:"tip",title:"Korean News Register",text:"Korean news has a distinct writing style:\n\nHeadline: short, no endings (noun-stop)\nLead: 것으로 나타났다, 것으로 알려졌다\nBody: -(으)며, -(으)로 인해, -에 의해\nQuote: -다고 밝혔다, -라고 전했다\n\nNews Korean is WRITTEN register.\nIt sounds strange in casual speech.",deepDive:"Korean news structure:\n\n1. 제목 (headline): as short as possible\n 서울 지하철 파업 (Seoul Subway Strike)\n\n2. 리드 (lead): summarizes the entire story\n 서울 지하철 노조가 파업을 결정한 것으로 알려졌다.\n\n3. 본문 (body): details in order of importance\n Uses formal connectors: -(으)며, -(으)로 인해\n\n4. 인용 (quote): attributed speech\n 관계자는 '협상을 계속하겠다'고 밝혔다.\n\nThis is the INVERTED PYRAMID structure.\nMost important information comes first."},
{type:"mc",q:"정부가 새 정책을 발표했습니다.\nWhat does 발표 mean?",opts:["Announcement","Investigation","Statistics","Accident"],ans:"Announcement",hint:"Send-show: making something publicly known."},
{type:"drag_fill",s:"경찰이 {1}을 {2}하고 있습니다.\n(Police are investigating the incident.)",blanks:{"1":"사건","2":"조사"},pool:["사건","조사","보도","발표","사고","통계"],hint:"The event. The act of examining systematically."},
{type:"mc",q:"교통사고로 인해 길이 막혔습니다.\nWhat happened?",opts:["Traffic was reported on the news","Road was blocked due to a traffic accident","An investigation found road problems","Statistics showed increased traffic"],ans:"Road was blocked due to a traffic accident",hint:"Break down the Sino-Korean: 사고 has 事 (matter) + 故 (incident). What did this cause on the road?"},
{type:"match",pairs:[{nl:"기사",en:"news article"},{nl:"보도",en:"news report"},{nl:"사건",en:"incident"},{nl:"통계",en:"statistics"}]},
{type:"fb",s:"{1}에 의하면 인구가 줄고 있습니다.\n(According to statistics, population is decreasing.)",a:"통계",opts:["통계","보도","사건","기사"],hint:"Total-count: numerical data about population."},
{type:"drag_fill",s:"{1}가 {2}을 {3}하{4} {5}도 함께 발표했습니다.\n(The government announced the policy, and also released statistics together.)",blanks:{"1":"정부","2":"정책","3":"발표","4":"며","5":"통계"},pool:["정부","정책","발표","며","통계","경찰","사건","조사","고","보도"],hint:"Government. Policy. Announce. Written 'and'. Numerical data."},
{type:"mc",q:"Which register does Korean news use?",opts:["Intimate (반말)","Casual spoken (해요체)","Written formal (-(으)며, -(으)므로, -에 의해)","Mixed formal and casual"],ans:"Written formal (-(으)며, -(으)므로, -에 의해)",hint:"News is WRITTEN register. Different from everyday speech."},
{type:"drag_fill",s:"이 {1}는 큰 {2}을 받았으{3} {4}가 {5}하고 있습니다.\n(This incident received great attention, and police are investigating.)",blanks:{"1":"사건","2":"관심","3":"며","4":"경찰","5":"조사"},pool:["사건","관심","며","경찰","조사","사고","보도","고","정부","발표"],hint:"Event. Interest. Written 'and'. Law enforcement. Examine."},
{type:"drag_fill",s:"{1}에 따르면 최근 {2}가 증가한 것으로 {3}.\n(According to reports, incidents have recently increased, it was revealed.)",blanks:{"1":"보도","2":"사건","3":"나타났다"},pool:["보도","사건","나타났다","통계","사고","알려졌다"],hint:"News report. Events. Revealed/shown."},

{type:"drag_fill",s:"오늘 뉴스{1} 보셨어요? 큰 사건{2} 있었{3}요.\n(Did you see today's news? There was a big incident.)",blanks:{"1":"를","2":"이","3":"어"},pool:["를","이","어","을","가","아","에","는"],hint:"Object. Subject. Past polite."},
{type:"mc",q:"통계에 따르면 vs 보도에 따르면:\n숫자 (numbers) relates to which?\n(Citing statistics vs news reports.)",opts:["Both are identical","보도 relates to 숫자","Neither relates","통계 relates to 숫자 .  both deal with numbers/data"],ans:"통계 relates to 숫자 .  both deal with numbers/data",hint:"This word about data and numbers is related to quantitative analysis."},
{type:"drag_fill",s:"그 사고{1} 대{2} 조사{3} 진행 중이에요. 발표{4} 아직 안 했어요.\n(Investigation is in progress regarding that accident. Announcement hasn't been made yet.)",blanks:{"1":"에","2":"해","3":"가","4":"를"},pool:["에","해","가","를","이","한","는","의"],hint:"About/regarding. About (대하다). Subject. Object."},
]},

// ── L2: 원인 — 으로 인해 (Due To) ──
{id:"kou23l2",title:"으로 인해",icon:"📋",xp:20,board:true,steps:[
{type:"intro",title:"Due To (Formal Cause)",desc:"-(으)로 인해(서)\n→ Formal 'due to' for news and academic writing.\n\nThis is the NEWS version of 때문에.\nUsed for external causes in formal contexts.",goals:["Use -(으)로 인해 in formal sentences","Distinguish from 때문에 (neutral) and -(으)므로 (logical)","Read news sentences with formal cause markers"]},
{type:"teach",kind:"grammar",nl:"-(으)로 인해(서)",en:"due to / because of (formal)",pos:"part",gender:null,funFact:"Korean particles attach after nouns to mark their role. No equivalent in English.",phonetic:"eu-ro in-hae",example:"A: 오늘 왜 이렇게 길이 막혀요? B: 폭우로 인해 도로가 침수되었대요. A: 정말요? 얼마나 심각해요? B: 뉴스에서 여러 곳이 통제되었다고 했어요. A: 출근은 어떻게 해요? B: 대중교통을 이용하라고 안내했습니다. A: 지하철은 괜찮아요? B: 일부 구간이 폭우로 인해 지연되고 있대요. A: 회사에 연락해야겠네요. B: 네, 저도 재택근무를 하려고요.",exampleEn:"A: Why is there so much traffic today? B: They said roads were flooded due to heavy rain. A: Really? How serious is it? B: The news said several areas are blocked. A: How do we get to work? B: They advised using public transport. A: Is the subway okay? B: Some sections are delayed due to heavy rain, they say. A: I should contact the office. B: Yes, I am planning to work from home too.",note:"Formal external cause marker.\nUsed in news, reports, and official documents.\nNoun + (으)로 인해(서)\n\n폭우 = heavy rain (暴雨)\n침수 = flooding (浸水)"},
{type:"tip",title:"으로 인해 vs 때문에",text:"Both mean 'because of', but differ in register:\n\n때문에: neutral, any context\n 비 때문에 못 갔어요.\n (Couldn't go because of rain.)\n\n(으)로 인해: formal, written\n 폭우로 인해 행사가 취소되었습니다.\n (The event was canceled due to heavy rain.)\n\n(으)로 인해 sounds strange in casual speech.\nUse 때문에 when talking to friends.",deepDive:"Additional formal cause patterns:\n\n(으)로 인한 + noun (adjective form)\n 폭우로 인한 피해 = damage due to heavy rain\n\n(으)로 말미암아 (very literary, rare)\n 전쟁으로 말미암아 = owing to the war\n\nThe pattern: Noun + (으)로 인해 + result\nThe cause is always EXTERNAL (not the subject's action).\n\nWrong: 제가 실수로 인해 (my mistake as cause)\nRight: 시스템 오류로 인해 (system error as cause)"},
{type:"mc",q:"폭우로 인해 도로가 침수되었습니다.\nWhat does 으로 인해 mean here?",opts:["Due to (formal cause)","Through / via","As a (role)","Instead of"],ans:"Due to (formal cause)",hint:"Formal news cause. Heavy rain caused flooding."},
{type:"fb",s:"교통{1}로 인해 출근이 지연되었습니다.\n(Commuting was delayed due to a traffic accident.)",a:"사고",opts:["사고","사건","기사","보도"],hint:"An unexpected event on the road."},
{type:"mc",q:"Which is the NEWS register version?\nA: 비 때문에 못 갔어요.\nB: 폭우로 인해 행사가 취소되었습니다.",opts:["A is news register (formal written)","B is news register (formal written)","Both are the same register","Neither is formal"],ans:"B is news register (formal written)",hint:"One pattern appears in news broadcasts, the other in everyday conversation. Which sentence sounds like a news anchor?"},
{type:"fb",s:"지진으로 {1} 건물이 무너졌습니다.\n(Buildings collapsed due to the earthquake.)",a:"인해",opts:["인해","때문에","의해","따라"],hint:"Formal 'due to' after a cause noun."},
{type:"teach",kind:"noun",nl:"피해",en:"damage / harm",pos:"noun",gender:null,funFact:"Sino-Korean compound: 피(suffer/被) + 해(harm/害)",phonetic:"pi-hae",example:"태풍으로 인해 큰 피해가 발생했습니다.\n(Great damage occurred due to the typhoon.)",exampleEn:"Great damage occurred due to the typhoon.",note:"COMPOUND: 피(suffer/被) + 해(harm/害).\nSuffer-harm: damage received.\n피해자 = victim (피해 + 자 person)."},
{type:"mc",q:"태풍으로 인한 피해가 심각합니다.\nWhat is 으로 인한?",opts:["Noun form: the cause of the typhoon","Verb form: the typhoon caused","Adjective form: damage CAUSED BY the typhoon","Adverb form: because of the typhoon"],ans:"Adjective form: damage CAUSED BY the typhoon",hint:"인한 (not 인해) modifies the following noun directly."},
{type:"drag_fill",s:"인구 감소로 {1} 학교가 폐교되{2}.\n(Schools are being closed due to population decline.) (news)",blanks:{"1":"인해","2":"고 있습니다"},pool:["인해","고 있습니다","때문에","었습니다","의해","습니다"],hint:"Formal cause. Progressive formal ending."},
{type:"drag_fill",s:"{1}로 인해 {2}가 {3}되{4} {5}가 {6}하고 있습니다.\n(Commuting was delayed due to heavy snow, and police are investigating.)",blanks:{"1":"폭설","2":"출근","3":"지연","4":"었으며","5":"경찰","6":"조사"},pool:["폭설","출근","지연","었으며","경찰","조사","폭우","사건","취소","었고","정부","발표"],hint:"Heavy snow. Commute. Delay. Written past + and. Law enforcement. Examine."},
{type:"mc",q:"다음 중 (으)로 인해를 쓸 수 없는 문장은?",opts:["감염병으로 인해 행사가 연기되었습니다 (disease)","태풍으로 인해 항공편이 취소되었습니다 (external event)","사고로 인해 도로가 통제되었습니다 (accident)","제가 늦게 일어나서로 인해 지각했어요 (personal action as cause)"],ans:"제가 늦게 일어나서로 인해 지각했어요 (personal action as cause)",hint:"This formal cause marker requires an external event or circumstance, not personal behavior."},
{type:"drag_fill",s:"최근 {1}로 인한 {2}가 증가하고 있{3} {4}가 필요합니다.\n(Damage from recent earthquakes is increasing, and investigation is needed.) (news)",blanks:{"1":"지진","2":"피해","3":"으며","4":"조사"},pool:["지진","피해","으며","조사","태풍","사건","고","발표"],hint:"Earthquake. Suffer-harm. Written 'and'. Systematic inquiry."},
{type:"drag_fill",s:"{1}에 따르면 {2}로 인해 {3}만 원의 {4}가 발생했습니다.\n(According to reports, 100 million won in damage occurred due to the accident.)",blanks:{"1":"보도","2":"사고","3":"1억","4":"피해"},pool:["보도","사고","1억","피해","통계","사건","천","손실"],hint:"News coverage. Unexpected event. 100 million. Suffer-harm."},

{type:"mc",q:"태풍으로 인해 비행기가 결항되었다.\n비행기 belongs to which vocabulary?\n(Due to typhoon, flights were cancelled.)",opts:["Travel/transport vocabulary ","Food vocabulary","Academic vocabulary","Body parts"],ans:"Travel/transport vocabulary ",hint:"transportation words."},
{type:"drag_fill",s:"인구 감소{1} 인해 학교{2} 줄어들고 있다. 경제 성장{1} 인해 일자리{2} 늘어나고 있다.\n(Due to population decline, schools are decreasing. Due to economic growth, jobs are increasing.)",blanks:{"1":"로","2":"가"},pool:["로","가","에","이","를","는","의","에서"],hint:"Formal cause (x2). Subject (x2)."},
{type:"drag_fill",s:"-기 때문에: {1} register, {2} cause.\n-(으)로 인해: {3} register, {4} cause.\n(Register comparison.)",blanks:{"1":"any","2":"subjective or objective","3":"formal/written","4":"external/objective"},pool:["any","subjective or objective","formal/written","external/objective","casual","internal","spoken","personal"],hint:"때문에=flexible. 으로 인해=news/formal, external events."},
{type:"drag_fill",s:"코로나{1} 인해 많{2} 사람들{3} 재택근무{4} 했다.\n(Due to COVID, many people worked from home.)",blanks:{"1":"로","2":"은","3":"이","4":"를"},pool:["로","은","이","를","에","는","가","의"],hint:"Formal cause. Many (modifier). Subject. Object."},

{type:"drag_fill",s:"폭우{1} 인해 도로{2} 침수되었다. 많{3} 차량{4} 피해{5} 입었다.\n(Due to heavy rain, roads were flooded. Many vehicles suffered damage.)",blanks:{"1":"로","2":"가","3":"은","4":"이","5":"를"},pool:["로","가","은","이","를","에","는","의","에서","도"],hint:"Formal cause. Subject. Many (modifier). Subject. Object."},
{type:"mc",q:"-(으)로 인해 is ONLY used for external events/causes.\nWhich sentence is WRONG?\n(Constraint of the formal cause pattern.)",opts:["지진으로 인해 피해가 발생했다","제가 피곤한 것으로 인해 .  WRONG: personal feeling, not external","코로나로 인해 학교가 문을 닫았다","폭설로 인해 교통이 마비되었다"],ans:"제가 피곤한 것으로 인해 .  WRONG: personal feeling, not external",hint:"The formal 'due to' requires an outside cause—not a personal feeling or action."},
{type:"drag_fill",s:"고령화{1} 인해 의료비{2} 증가하{3} 있다. 이{4} 심각{5} 문제다.\n(Due to aging population, medical costs are increasing. This is a serious problem.)",blanks:{"1":"로","2":"가","3":"고","4":"는","5":"한"},pool:["로","가","고","는","한","에","이","어","을","의"],hint:"Formal cause. Subject. Progressive. Topic. Modifier."},
]},

// ── L3: 행위자 — 에 의해 (By) ──
{id:"kou23l3",title:"에 의해",icon:"🔍",xp:20,board:true,steps:[
{type:"intro",title:"By (Passive Agent Marker)",desc:"-에 의해(서)\n→ Formal passive 'by' for news writing.\n\nWho DID it? In Korean news, the doer is marked\nwith -에 의해, not the subject.",goals:["Use -에 의해 to mark the agent in passive sentences","Distinguish 에 의해 (by) from 으로 인해 (due to)","Transform active sentences to passive news style"]},
{type:"teach",kind:"grammar",nl:"-에 의해(서)",en:"by (passive agent marker)",pos:"part",gender:null,funFact:"Marks location or time. One particle, two jobs. Context tells you which.",phonetic:"e ui-hae",example:"A: 이 법은 어떻게 통과되었어요? B: 국회에 의해 통과되었습니다. A: 누가 발의했어요? B: 여당 의원에 의해 발의되었다고 해요. A: 반대는 없었어요? B: 일부 반대가 있었지만 과반수가 찬성했습니다. A: 언제부터 시행되나요? B: 다음 달부터 시행될 예정이래요. A: 국민들 반응은 어때요? B: 전문가에 의해 긍정적으로 평가되고 있습니다.",exampleEn:"A: How was this law passed? B: It was passed by the National Assembly. A: Who proposed it? B: It was proposed by a ruling party member, they say. A: Was there no opposition? B: There was some opposition, but the majority voted in favor. A: When does it take effect? B: It is scheduled to take effect next month. A: How are people reacting? B: It is being positively evaluated by experts.",note:"Marks WHO did the action in passive sentences.\n에 의해 = by (agent)\n으로 인해 = due to (cause)\n\nActive: 국회가 법을 통과시켰다.\nPassive: 법이 국회에 의해 통과되었다."},
{type:"tip",title:"에 의해 vs 으로 인해",text:"Both are formal, but different roles:\n\n에 의해: WHO did it (agent)\n 범인이 경찰에 의해 체포되었습니다.\n (The criminal was arrested BY police.)\n\n으로 인해: WHAT caused it (cause)\n 폭우로 인해 도로가 막혔습니다.\n (Roads were blocked DUE TO heavy rain.)\n\nTest: can you replace with 'by someone'?\nYes = 에 의해. No = 으로 인해.",deepDive:"에 의한 (adjective form) + noun:\n 전문가에 의한 분석 = analysis BY experts\n\n에 의하면 (according to):\n 보도에 의하면 = according to reports\n This is a DIFFERENT usage: 'according to'\n NOT passive agent. Context decides.\n\nFormal passive pattern:\n Active: A가 B를 V-했다\n Passive: B가 A에 의해 V-되었다\n\nKorean news LOVES passive voice.\nIt sounds objective and authoritative."},
{type:"mc",q:"범인이 경찰에 의해 체포되었습니다.\nWhat role does 에 의해 play?",opts:["Marks the agent (who did it): police arrested","Marks the cause: because of police","Marks the location: at the police station","Marks the time: during the police operation"],ans:"Marks the agent (who did it): police arrested",hint:"에 의해 = by. The police are the ones who arrested."},
{type:"fb",s:"이 건물은 유명한 건축가{1} 의해 설계되었습니다.\n(This building was designed by a famous architect.)",a:"에",opts:["에","로","가","를"],hint:"Passive agent marker particle."},
{type:"mc",q:"A: 태풍으로 인해 피해가 발생했습니다.\nB: 이 보고서는 전문가에 의해 작성되었습니다.\nWhich uses a passive agent?",opts:["A: 으로 인해 marks the agent (typhoon)","B: 에 의해 marks who wrote it (experts)","Both mark agents","Neither marks agents"],ans:"B: 에 의해 marks who wrote it (experts)",hint:"One marks WHO performed the action, the other marks WHAT caused the situation. Think agent vs cause."},
{type:"drag_fill",s:"이 {1}은 기자{2} 의해 보도되었습니다.\n(This incident was reported by a journalist.)",blanks:{"1":"사건","2":"에"},pool:["사건","에","사고","로","기사","가"],hint:"An event. Passive agent particle."},
{type:"teach",kind:"noun",nl:"체포",en:"arrest",pos:"noun",gender:null,funFact:"Sino-Korean compound: 체(body/體) + 포(catch/捕)",phonetic:"che-po",example:"용의자가 경찰에 의해 체포되었습니다.\n(The suspect was arrested by police.)",exampleEn:"The suspect was arrested by police.",note:"COMPOUND: 체(body/體) + 포(catch/捕).\nBody-catch: physically apprehending someone.\n체포하다 = to arrest."},
{type:"mc",q:"Active: 정부가 정책을 발표했습니다.\nPassive (news style):",opts:["정부가 정책에 의해 발표되었습니다","정책을 정부로 인해 발표되었습니다","정책이 정부에 의해 발표되었습니다","정책이 정부가 발표되었습니다"],ans:"정책이 정부에 의해 발표되었습니다",hint:"In a passive construction, the original subject becomes the agent marked with a particle."},
{type:"drag_fill",s:"용의자가 {1}에 의해 {2}되었{3} {4}이 진행 중입니다.\n(The suspect was arrested by police, and investigation is in progress.) (news)",blanks:{"1":"경찰","2":"체포","3":"으며","4":"조사"},pool:["경찰","체포","으며","조사","정부","발표","고","보도"],hint:"Law enforcement. Body-catch. Written 'and'. Systematic inquiry."},
{type:"drag_fill",s:"{1}에 의하면 이 {2}은 {3}에 의해 {4}된 것으로 알려졌습니다.\n(According to reports, this building was designed by a famous architect, it was reported.)",blanks:{"1":"보도","2":"건물","3":"유명한 건축가","4":"설계"},pool:["보도","건물","유명한 건축가","설계","통계","사건","경찰","체포"],hint:"News coverage. Structure. Famous designer. Design."},
{type:"mc",q:"에 의하면 can mean 'according to'.\n보도에 의하면 = ?",opts:["Through the reports","By the reports","Due to the reports","According to reports"],ans:"According to reports",hint:"에 의하면 in this context = 'according to', not passive."},
{type:"drag_fill",s:"전문가{1} 의한 {2} 결과가 발표되었습니다.\n(Analysis results by experts were announced.)",blanks:{"1":"에","2":"분석"},pool:["에","분석","로","조사","가","통계"],hint:"Agent particle. Detailed examination word."},
{type:"drag_fill",s:"{1}로 인해 {2}가 발생했{3} {4}에 의해 {5}가 진행되고 있습니다.\n(Damage occurred due to the earthquake, and investigation is being conducted by the government.)",blanks:{"1":"지진","2":"피해","3":"으며","4":"정부","5":"조사"},pool:["지진","피해","으며","정부","조사","태풍","사건","고","경찰","보도"],hint:"Earthquake. Damage. Written 'and'. Government. Inquiry."},

{type:"mc",q:"이 건물은 유명한 건축가에 의해 설계되었다.\n-에 의해 marks the AGENT in passive.\n-이/가 marks?\n(This building was designed by a famous architect.)",opts:["-이/가 = subject marker ","이/가 = object","이/가 = location","이/가 = time"],ans:"-이/가 = subject marker ",hint:"subject particle, different from passive agent."},
{type:"drag_fill",s:"이 법{1} 국회{2} 의해 통과되었다. 새 정책{1} 정부{2} 의해 발표되었다.\n(This law was passed by the National Assembly. New policy was announced by the government.)",blanks:{"1":"은","2":"에"},pool:["은","에","이","를","는","의","가","에서"],hint:"Topic (x2). Passive agent (x2)."},
{type:"mc",q:"-(으)로 인해 vs -에 의해:\n홍수로 인해 피해가 발생했다. (cause)\n대통령에 의해 발표되었다. (agent)\nKey difference?\n(Cause vs agent in formal Korean.)",opts:["Same meaning","로 인해 = cause/reason; 에 의해 = doer/agent","로 인해 = agent; 에 의해 = cause","Both mark cause"],ans:"로 인해 = cause/reason; 에 의해 = doer/agent",hint:"Two formal markers: one for cause (event-based), one for passive agent (person/org)."},
{type:"drag_fill",s:"전문가{1} 의해 조사{2} 진행되었다. 그 결과{3} 의하면 안전하다.\n(The investigation was conducted by experts. According to the results, it is safe.)",blanks:{"1":"에","2":"가","3":"에"},pool:["에","가","에","를","이","의","는","에서"],hint:"Passive agent. Subject. According to."},
{type:"drag_fill",s:"-(으)로 인해: {1} caused {2}.\n-에 의해: {3} did the action.\n-에 의하면: {4} the source.\n(Three formal patterns.)",blanks:{"1":"event/situation","2":"result","3":"person/organization","4":"according to"},pool:["event/situation","result","person/organization","according to","time","cause","thing","despite"],hint:"인해=cause. 의해=agent. 의하면=citation."},

{type:"drag_fill",s:"이 보고서{1} 전문가{2} 의해 작성되었다. 쓰다{3} 작성하다{4} 같{5} 뜻이에요.\n(This report was written by experts. 쓰다 and 작성하다 have similar meanings.)",blanks:{"1":"는","2":"에","3":"와","4":"는","5":"은"},pool:["는","에","와","는","은","이","를","가","의","도"],hint:"Topic. Passive agent. And/with. Topic. Same (modifier)."},
{type:"mc",q:"에 의해 passive vs -아/어지다 passive:\n전문가에 의해 분석되었다 (by experts).\n상황이 좋아졌어요 (situation improved).\nDifference?\n(Two passive constructions.)",opts:["에 의해 is casual","Same construction","에 의해: agent specified (who did it); 아/어지다: no agent needed","아/어지다 needs an agent"],ans:"에 의해: agent specified (who did it); 아/어지다: no agent needed",hint:"에 의해 tells you WHO. 아/어지다 just says it changed."},
]},

// ── L4: 조건 — 에 따라 (Depending On / According To) ──
{id:"kou23l4",title:"에 따라",icon:"📊",xp:20,board:true,steps:[
{type:"intro",title:"Depending On / According To",desc:"-에 따라(서)\n→ 'Depending on' or 'according to'.\n\nTwo uses in one pattern:\n1. 상황에 따라 = depending on the situation\n2. 보도에 따르면 = according to reports",goals:["Use -에 따라 for conditional variation","Use -에 따르면 for citing sources","Distinguish the two meanings in context"]},
{type:"teach",kind:"grammar",nl:"-에 따라(서)",en:"depending on / according to",pos:"part",gender:null,funFact:"Marks location or time. One particle, two jobs. Context tells you which.",phonetic:"e tta-ra",example:"A: 이번 프로젝트 일정이 확정되었나요? B: 아직이요. 결과에 따라 계획이 달라질 수 있어요. A: 그럼 언제쯤 결정돼요? B: 다음 주 회의에서 결정될 거예요. A: 팀원들에게 알려야 할까요? B: 네, 상황에 따라 유연하게 대응하자고 전해 주세요. A: 예산도 변경될 수 있나요? B: 네, 규모에 따라 예산이 조정됩니다. A: 알겠습니다. 보고서를 준비할게요. B: 좋아요. 부서에 따라 양식이 다르니까 확인하세요.",exampleEn:"A: Has the project schedule been finalized? B: Not yet. Plans may change depending on results. A: Then when will it be decided? B: It will be decided at next week's meeting. A: Should I inform the team members? B: Yes, please tell them to respond flexibly depending on the situation. A: Could the budget change too? B: Yes, the budget is adjusted depending on the scale. A: Understood. I will prepare the report. B: Good. Check the format since it differs depending on the department.",note:"Two distinct meanings:\n\n1. Depending on: 상황에 따라 다릅니다.\n (It differs depending on the situation.)\n\n2. According to: 보도에 따르면...\n (According to reports...)"},
{type:"tip",title:"에 따라 Two Faces",text:"Same grammar, two uses:\n\nConditional: 에 따라 + varies\n 나라에 따라 문화가 다릅니다.\n (Culture differs depending on country.)\n\nCitation: 에 따르면\n 전문가에 따르면 문제가 심각합니다.\n (According to experts, the problem is serious.)\n\nTip: 에 따르면 always cites a SOURCE.\n에 따라 다르다 shows VARIATION.",deepDive:"Related forms:\n\n에 따른 (adjective form)\n 상황에 따른 대응 = response according to situation\n\n에 따라서 (longer form, same meaning)\n 결과에 따라서 = depending on results\n\nIn news:\n 조사에 따르면 = according to a survey\n 통계에 따르면 = according to statistics\n 관계자에 따르면 = according to officials\n\nThese are STANDARD news citation phrases.\nYou will see them in every Korean article."},
{type:"mc",q:"나라에 따라 문화가 다릅니다.\nWhat meaning of 에 따라?",opts:["Depending on (conditional variation)","According to (citation)","Due to (cause)","By means of (method)"],ans:"Depending on (conditional variation)",hint:"Culture VARIES depending on country. Conditional meaning."},
{type:"fb",s:"{1}에 따르면 올해 경제가 성장할 것입니다.\n(According to statistics, the economy will grow this year.)",a:"통계",opts:["통계","사건","피해","사고"],hint:"Numerical data. Citation source."},
{type:"mc",q:"전문가에 따르면 문제가 심각합니다.\nWhat meaning of 에 따르면?",opts:["Depending on (conditional)","According to (citing a source)","Due to (cause)","By (agent)"],ans:"According to (citing a source)",hint:"Citing experts as the source of information."},
{type:"drag_fill",s:"결과{1} 따라 계획이 달라{2} 수 있습니다.\n(Plans may change depending on results.)",blanks:{"1":"에","2":"질"},pool:["에","질","로","할","가","될"],hint:"Particle before 따라. Potential change verb."},
{type:"teach",kind:"noun",nl:"전문가",en:"expert / specialist",pos:"noun",gender:null,funFact:"Sino-Korean compound: 전(special/專) + 문(field/門) + 가(person/家)",phonetic:"jeon-mun-ga",example:"전문가에 따르면 상황이 나아질 것입니다.\n(According to experts, the situation will improve.)",exampleEn:"According to experts, the situation will improve.",note:"COMPOUND: 전(special/專) + 문(field/門) + 가(person/家).\nSpecial-field-person: someone with deep knowledge.\n전문 분야 = area of expertise."},
{type:"mc",q:"Which pairs correctly?\nA: 보도에 따르면 (according to reports)\nB: 상황에 따라 (depending on situation)\nC: 사고로 인해 (due to accident)",opts:["Only A and C are correct","Only A and B are correct","All three are correct","Only B and C are correct"],ans:"All three are correct",hint:"Each sentence uses a different formal connector. Check if all three correctly match their function."},
{type:"drag_fill",s:"{1}에 따르면 {2}로 인해 {3}가 증가했습니다.\n(According to reports, damage increased due to the earthquake.)",blanks:{"1":"보도","2":"지진","3":"피해"},pool:["보도","지진","피해","통계","태풍","사건"],hint:"News coverage (source). Earthquake (cause). Suffer-harm (result)."},
{type:"drag_fill",s:"{1}에 따르면 {2}에 따라 {3}이 다{4} {5}가 필요합니다.\n(According to experts, treatment differs depending on symptoms, and investigation is needed.)",blanks:{"1":"전문가","2":"증상","3":"치료","4":"르며","5":"조사"},pool:["전문가","증상","치료","르며","조사","통계","결과","계획","고","발표"],hint:"Specialist. Symptoms. Treatment. Written differ + and. Inquiry."},
{type:"mc",q:"에 따른 is the adjective form.\n상황에 따른 대응 means:",opts:["Response by the situation","Response despite the situation","Response due to the situation","Response according to the situation"],ans:"Response according to the situation",hint:"에 따른 + noun = noun that follows/matches X."},
{type:"drag_fill",s:"{1}에 의해 작성된 {2}에 따르면 {3}로 인한 {4}가 심각합니다.\n(According to a report written by experts, damage due to pollution is serious.)",blanks:{"1":"전문가","2":"보고서","3":"오염","4":"피해"},pool:["전문가","보고서","오염","피해","경찰","기사","사고","사건"],hint:"Specialists. Written document. Contamination. Suffer-harm."},

{type:"mc",q:"나라에 따라 문화가 다릅니다.\n나라 here means?\n(Culture differs depending on the country.)",opts:["나라 = country ","나라 = city","나라 = house","나라 = school"],ans:"나라 = country ",hint:"geography vocabulary."},
{type:"drag_fill",s:"전문가{1} 따르면 경제{2} 회복될 것이다. 상황{3} 따라 계획{4} 바뀔 수 있다.\n(According to experts, economy will recover. Plans can change depending on the situation.)",blanks:{"1":"에","2":"가","3":"에","4":"이"},pool:["에","가","에","이","를","는","의","에서"],hint:"According-to. Subject. Depending-on. Subject."},
{type:"mc",q:"-에 따라 has THREE uses:\n1. Depending on (variation)\n2. According to (citation)\n3. In accordance with (compliance)\nWhich form is used for citing news?\n(Three uses of the same pattern.)",opts:["에 따라서 (depending on)","-에 따르면 (according to .  citation form)","에 따른 (modifier form)","에 따라 (all three)"],ans:"-에 따르면 (according to .  citation form)",hint:"The citation form meaning 'according to' follows a source noun."},
{type:"drag_fill",s:"보도{1} 따르면 사고{2} 원인{3} 조사 중이다. 날씨{1} 따라 일정{4} 변경될 수 있다.\n(According to reports, the cause of accident is under investigation. Schedule may change depending on weather.)",blanks:{"1":"에","2":"의","3":"이","4":"이"},pool:["에","의","이","이","를","가","는","에서"],hint:"According-to / depending-on. Possessive. Subject. Subject."},
{type:"drag_fill",s:"-에 따르면: {1} says X.\n-에 따라(서): {2} on factor.\n-에 따른: {3} form (noun modifier).\n(Three forms of 에 따라.)",blanks:{"1":"source","2":"depending","3":"adjective"},pool:["source","depending","adjective","cause","because","verb","agent","passive"],hint:"따르면=citation. 따라서=variation. 따른=modifier."},
{type:"drag_fill",s:"조사{1} 따르면 국민{2} 70%{3} 찬성했다. 연령{1} 따라 결과{4} 달랐다.\n(According to survey, 70% of citizens agreed. Results differed by age group.)",blanks:{"1":"에","2":"의","3":"가","4":"가"},pool:["에","의","가","가","를","이","는","에서"],hint:"According-to. Possessive. Subject (70%). Subject."},
{type:"mc",q:"뉴스에 따르면 내일 비가 온다고 합니다.\n-다고 하다 means?\n(According to news, it is said it will rain tomorrow.)",opts:["하다 = to do","다고 = because","-다고 하다 = indirect speech / it is said that ","다고 = even though"],ans:"-다고 하다 = indirect speech / it is said that ",hint:"reported speech pattern."},
{type:"drag_fill",s:"법{1} 따라 처리해야 합니다. 규정{1} 따{2} 행동은 처벌 대상이다.\n(Must handle according to law. Actions not following regulations are subject to punishment.)",blanks:{"1":"에","2":"르지 않"},pool:["에","르지 않","를","는","의","에서","르는","은"],hint:"In-accordance-with. Not following (negative)."},
{type:"mc",q:"전문가에 따르면 vs 전문가에 의하면:\nBoth cite experts. Difference?\n(Two citation patterns compared.)",opts:["의하면 is casual","Same meaning","따르면 is more formal","따르면 = general citation; 의하면 = based on formal report/study"],ans:"따르면 = general citation; 의하면 = based on formal report/study",hint:"Two 'according to' expressions: one general, one based on research findings."},
]},

// ── L5: 결과 — 것으로 나타났다 (It Was Found That) ──
{id:"kou23l5",title:"것으로 나타났다",icon:"📈",xp:20,board:true,steps:[
{type:"intro",title:"News Result Cliches",desc:"것으로 나타났다 / 보인다 / 알려졌다\n→ Standard Korean news phrases for reporting findings.\n\nEvery Korean news article uses these.\nThey are the 'it was found that' of Korean journalism.",goals:["Recognize news result cliche patterns","Use 나타났다, 보인다, 알려졌다 correctly","Read Korean news headlines and leads"]},
{type:"teach",kind:"grammar",nl:"것으로 나타났다",en:"it was found/shown that",pos:"part",gender:null,funFact:"Korean particles attach after nouns to mark their role. No equivalent in English.",phonetic:"geo-seu-ro na-ta-nat-da",example:"A: 오늘 뉴스 보셨어요? B: 네, 경제가 회복되고 있는 것으로 나타났대요. A: 정말요? 어떤 조사 결과예요? B: 한국은행 발표에 따르면 성장률이 올랐대요. A: 체감은 안 되는데요. B: 맞아요. 통계와 실제 생활은 차이가 있죠. A: 고용 시장은 어때요? B: 취업률도 개선된 것으로 나타났다고 해요. A: 그래도 청년 실업은 여전하죠? B: 네, 그 부분은 아직 심각한 것으로 보인다고 합니다.",exampleEn:"A: Did you see today's news? B: Yes, it was found that the economy is recovering. A: Really? What survey results? B: According to the Bank of Korea, the growth rate went up. A: I don't feel it though. B: Right. There's a gap between statistics and real life. A: How is the job market? B: They say the employment rate was also found to have improved. A: But youth unemployment is still the same, right? B: Yes, they say that area still appears to be serious.",note:"News cliche for reporting survey/research results.\nLiterally: 'appeared as the thing that'\n\nVariants:\n것으로 보인다 = it appears that\n것으로 알려졌다 = it was reported that"},
{type:"teach",kind:"grammar",nl:"-다시피",en:"as (you know/see/heard)",pos:"part",gender:null,funFact:"Korean particles attach after nouns to mark their role. No equivalent in English.",phonetic:"da-si-pi",example:"A: 한국 기업들이 왜 이렇게 잘해요? B: 아시다시피 한국은 IT 강국이잖아요. A: 교육 시스템 덕분인가요? B: 그것도 있고, 투자도 많이 하죠. A: 보시다시피 성과가 대단하네요. B: 네, 앞으로도 발전할 것으로 보입니다. A: 다른 나라들도 따라올 수 있을까요? B: 들으시다시피 경쟁이 치열해지고 있어요. A: 한국만의 강점이 있나요? B: 아시다시피 빠른 인터넷과 교육열이 핵심이죠.",exampleEn:"A: Why do Korean companies do so well? B: As you know, Korea is an IT powerhouse. A: Is it thanks to the education system? B: That too, and they invest a lot. A: As you can see, the results are impressive. B: Yes, it appears they will continue to develop. A: Can other countries catch up? B: As you have heard, competition is getting fierce. A: Does Korea have unique strengths? B: As you know, fast internet and passion for education are the key.",note:"Connects to shared knowledge.\n알다 → 아시다시피 (as you know, formal)\n보다 → 보시다시피 (as you see)\n듣다 → 들으시다시피 (as you heard)\n\nC1 seed: -는 바 (formal 'the fact that')"},
{type:"tip",title:"News Cliche Set",text:"These three phrases appear in EVERY Korean article:\n\n것으로 나타났다 = it was found that\n (survey/research results)\n\n것으로 보인다 = it appears that\n (inference from evidence)\n\n것으로 알려졌다 = it was reported that\n (information from sources)\n\nAll follow: V-(으)ㄴ/는/(으)ㄹ 것으로 + ending",deepDive:"Full pattern forms:\n\nPast: V-(으)ㄴ 것으로 나타났다\n 감소한 것으로 나타났다 (found to have decreased)\n\nPresent: V-는 것으로 보인다\n 증가하는 것으로 보인다 (appears to be increasing)\n\nFuture: V-(으)ㄹ 것으로 알려졌다\n 시행될 것으로 알려졌다 (reported to be implemented)\n\nThese are VERY formal. Never use them in conversation.\nThey signal: 'I am writing a news article.'"},
{type:"mc",q:"경제가 회복되고 있는 것으로 나타났다.\nThis is typical of:",opts:["News writing (reporting survey findings)","Casual conversation","Text messaging","Academic thesis"],ans:"News writing (reporting survey findings)",hint:"것으로 나타났다 is a standard news cliche."},
{type:"fb",s:"인구가 감소하고 있는 것으로 {1}.\n(It was found that the population is decreasing.)",a:"나타났다",opts:["나타났다","보인다","알려졌다","밝혀졌다"],hint:"Research/survey result. 'Found that'."},
{type:"mc",q:"아시다시피 한국은 IT 강국입니다.\nWhat does 아시다시피 mean?",opts:["It was found that","As you know","According to","Due to"],ans:"As you know",hint:"알다 means to know. What does adding -다시피 do to the verb?"},
{type:"drag_fill",s:"새 정책이 시행{1} 것으로 {2}.\n(It was reported that a new policy will be implemented.)",blanks:{"1":"될","2":"알려졌다"},pool:["될","알려졌다","된","나타났다","하는","보인다"],hint:"Future implementation. 'Was reported that'."},
{type:"mc",q:"Match the nuance:\n나타났다 vs 보인다 vs 알려졌다",opts:["나타났다 is casual, 보인다 is formal","All three mean exactly the same thing","나타났다 (data shows), 보인다 (appears), 알려졌다 (reported)","알려졌다 is negative, others are positive"],ans:"나타났다 (data shows), 보인다 (appears), 알려졌다 (reported)",hint:"Each carries a different evidence base."},
{type:"fb",s:"{1}다시피 이 문제는 심각합니다.\n(As you know, this problem is serious.)",a:"아시",opts:["아시","보시","들으시","하시"],hint:"Know + 다시피. 'As you know' (formal)."},
{type:"drag_fill",s:"{1}에 따르면 실업률이 증가한 것으로 {2}{3} {4}다시피 경제 상황이 좋지 않습니다.\n(According to statistics, it was found that unemployment increased. As you know, the economic situation is not good.)",blanks:{"1":"통계","2":"나타났","3":"습니다.","4":"아시"},pool:["통계","나타났","습니다.","아시","보도","알려졌","어요.","보시"],hint:"Numerical data. Found that. Formal ending. Know + as."},
{type:"mc",q:"보시다시피 피해가 심각합니다.\n보시다시피 comes from:",opts:["보살피다 (to care) + 다시피","보이다 (to appear) + 다시피","보도 (report) + 다시피","보다 (to see) + 다시피 = as you see"],ans:"보다 (to see) + 다시피 = as you see",hint:"The compound is: a verb of visual perception + an 'as one does' suffix. Which basic verb contributes the seeing meaning?"},
{type:"drag_fill",s:"{1}로 인해 경제가 악화된 것으로 {2}{3} {4}에 의해 {5}가 진행되고 있습니다.\n(It appears the economy worsened due to the pandemic, and investigation is being conducted by the government.)",blanks:{"1":"감염병","2":"보이","3":"며","4":"정부","5":"조사"},pool:["감염병","보이","며","정부","조사","태풍","나타났","고","경찰","발표"],hint:"Disease. Appears. Written 'and'. Government. Inquiry."},
{type:"drag_fill",s:"{1}에 의하면 올해 출생률이 {2}한 것으로 {3} {4}다시피 심각한 문제입니다.\n(According to experts, it was found that the birth rate decreased this year. As you know, it is a serious problem.)",blanks:{"1":"전문가","2":"감소","3":"나타났습니다.","4":"아시"},pool:["전문가","감소","나타났습니다.","아시","통계","증가","알려졌습니다.","보시"],hint:"Specialists. Decrease. Found that + formal. Know + as."},

{type:"mc",q:"조사 결과, 청소년의 80%가 스마트폰을 사용하는 것으로 나타났다.\n사용하다 here means?\n(Survey showed 80% of teens use smartphones.)",opts:["사용하다 = to use ","사용하다 = to buy","사용하다 = to make","사용하다 = to sell"],ans:"사용하다 = to use ",hint:"basic verb from Sino-Korean 使用."},
{type:"drag_fill",s:"실험 결과 효과{1} 있{2} 것으로 나타났다. 다들 아시다시{3} 이 문제{4} 심각하다.\n(Experiment showed there is an effect. As you all know, this problem is serious.)",blanks:{"1":"가","2":"는","3":"피","4":"는"},pool:["가","는","피","는","를","은","다","이"],hint:"Subject. Present modifier. As-you-know. Topic."},
{type:"mc",q:"것으로 나타났다 vs 것으로 보인다 vs 것으로 알려졌다:\nWhich expresses the LEAST certainty?\n(Three news cliche patterns.)",opts:["나타났다 (was revealed .  certain)","보인다 (it appears/seems .  least certain)","알려졌다 (became known .  certain)","All equal certainty"],ans:"보인다 (it appears/seems .  least certain)",hint:"보이다 = to appear/seem. Less definitive."},
{type:"drag_fill",s:"관계자{1} 따르면 내년{2} 변화{3} 있{4} 것으로 보인다.\n(According to officials, it appears there will be changes next year.)",blanks:{"1":"에","2":"에","3":"가","4":"을"},pool:["에","에","가","을","의","는","이","는"],hint:"According-to. Time-at. Subject. Future modifier."},
{type:"drag_fill",s:"것으로 나타났다: {1} revealed by data.\n것으로 보인다: {2} but uncertain.\n것으로 알려졌다: {3} became public.\n(News certainty levels.)",blanks:{"1":"fact","2":"appears so","3":"information"},pool:["fact","appears so","information","opinion","rumor","denied","confirmed","false"],hint:"나타났다=shown. 보인다=seems. 알려졌다=known."},
{type:"drag_fill",s:"아시다시{1} 한국어{2} 어렵지만 재미있어요. 연구{3} 의하면 효과{4} 큰 것으로 나타났다.\n(As you know, Korean is hard but fun. According to research, the effect was shown to be big.)",blanks:{"1":"피","2":"는","3":"에","4":"가"},pool:["피","는","에","가","다","를","의","이"],hint:"As-you-know. Topic. According-to. Subject."},
]},

// ── L6: 추측 — 모양이다 vs 걸 보니 (Inference) ──
{id:"kou23l6",title:"모양이다 vs 걸 보니",icon:"🔮",xp:20,board:true,steps:[
{type:"intro",title:"It Seems / Judging By",desc:"모양이다 vs 걸 보니(까)\n→ Two inference patterns based on evidence.\n\n모양이다: it seems (from what I observe)\n걸 보니: judging by (what I see/know)",goals:["Use 모양이다 for evidence-based inference","Use 걸 보니 for observation-based judgment","Choose the right inference pattern for context"]},
{type:"teach",kind:"grammar",nl:"-(으)ㄴ/는 모양이다",en:"it seems / it appears that",pos:"aux",gender:null,funFact:"Korean verb endings change meaning dramatically. Mastering endings is the key to fluency.",phonetic:"mo-yang-i-da",example:"A: 밖에 사람들이 다 우산을 쓰고 있어요. B: 비가 오는 모양이에요. A: 저는 우산을 안 가져왔는데요. B: 편의점에서 사면 돼요. A: 오래 올 거 같아요? B: 하늘을 보니 금방 그칠 모양이에요. A: 내일도 비가 온대요? B: 예보를 보니 내일은 맑을 모양이에요. A: 다행이네요. 소풍 가기로 했거든요. B: 좋겠네요. 날씨가 도와줄 모양이에요.",exampleEn:"A: Everyone outside is carrying umbrellas. B: It seems it's raining. A: I didn't bring an umbrella. B: You can buy one at the convenience store. A: Do you think it will rain long? B: Looking at the sky, it seems it will stop soon. A: Is it supposed to rain tomorrow too? B: Looking at the forecast, it seems it will be clear tomorrow. A: That's a relief. We planned a picnic. B: Nice. It seems the weather will cooperate.",note:"Inference from indirect evidence.\nYou see SIGNS and conclude.\n\nPast: V-(으)ㄴ 모양이다\n 갔다 온 모양이에요 (seems they went)\nPresent: V-는 모양이다\n 바쁜 모양이에요 (seems busy)\nFuture: V-(으)ㄹ 모양이다\n 올 모양이에요 (seems they'll come)"},
{type:"teach",kind:"grammar",nl:"-(으)ㄴ/는 걸 보니(까)",en:"judging by / seeing that",pos:"part",gender:null,funFact:"Korean particles attach after nouns to mark their role. No equivalent in English.",phonetic:"geol bo-ni",example:"A: 과장님이 오늘 기분이 좋아 보여요. B: 표정이 밝은 걸 보니 좋은 소식인 모양이에요. A: 혹시 프로젝트가 승인되었나 봐요. B: 아까 회의실에서 나오면서 웃던데요. A: 그러면 우리도 좋은 소식이겠네요. B: 곧 공지가 있을 걸 보니 확실한 모양이에요. A: 팀 회식도 할까요? B: 과장님이 예약하는 걸 보니 그런 모양이에요. A: 어디로 가는지 아세요? B: 맛집을 검색하는 걸 보니 새로운 곳인 모양이에요.",exampleEn:"A: The section chief looks happy today. B: Judging by the bright expression, it seems like good news. A: Maybe the project was approved. B: I noticed they were smiling coming out of the meeting room. A: Then it would be good news for us too. B: Judging by an announcement coming soon, it seems certain. A: Will we have a team dinner too? B: Judging by the chief making a reservation, it seems so. A: Do you know where we are going? B: Judging by the search for good restaurants, it seems like a new place.",note:"Observation leads to a conclusion.\n걸 = 것을 (thing + object marker)\n보니 = having seen/looked\n\nPattern: evidence + 걸 보니 + conclusion\nOften pairs with 모양이다 in the conclusion."},
{type:"tip",title:"모양이다 vs 걸 보니",text:"Both are inference, but different focus:\n\n모양이다: the CONCLUSION (it seems that)\n 바쁜 모양이에요.\n (It seems [they're] busy.)\n\n걸 보니: the EVIDENCE (judging by)\n 전화를 안 받는 걸 보니 바쁜 모양이에요.\n (Judging by not answering, seems busy.)\n\nThey often appear TOGETHER:\n evidence + 걸 보니 → conclusion + 모양이다",deepDive:"Similar inference patterns (review):\n\n-(으)ㄴ/는 것 같다: general guess\n 바쁜 것 같아요 (I think they're busy)\n\n모양이다: evidence-based inference\n 바쁜 모양이에요 (it APPEARS busy = I see signs)\n\n걸 보니: names the specific evidence\n 전화를 안 받는 걸 보니 (judging by no answer)\n\n것 같다 is the weakest (just opinion).\n모양이다 is moderate (I see signs).\n걸 보니 explicitly states what you observed."},
{type:"mc",q:"비가 오는 모양이에요.\nWhat kind of statement is this?",opts:["Inference from evidence (it seems like rain)","Certainty (it is raining)","Wish (I hope it rains)","Command (make it rain)"],ans:"Inference from evidence (it seems like rain)",hint:"모양이다 = it seems/appears based on what I observe."},
{type:"drag_fill",s:"사람들이 코트를 입은 걸 {1} 날씨가 추운 {2}이에요.\n(Judging by people wearing coats, it seems the weather is cold.)",blanks:{"1":"보니","2":"모양"},pool:["보니","모양","보면","편"],hint:"Observation-judgment. Evidence-based seeming."},
{type:"mc",q:"전화를 안 받는 걸 보니 바쁜 모양이에요.\nWhich part is the EVIDENCE?",opts:["바쁜 모양이에요 (seems busy)","전화를 안 받는 걸 보니 (judging by not answering)","전화를 안 받는 (not answering)","모양이에요 (it seems)"],ans:"전화를 안 받는 걸 보니 (judging by not answering)",hint:"Evidence marker followed by a conclusion: judging by what is seen, the inference follows."},
{type:"drag_fill",s:"길이 젖은 {1} 보니 비가 {2} 모양이에요.\n(Judging by the wet roads, it seems it rained.)",blanks:{"1":"걸","2":"온"},pool:["걸","온","것을","오는","데","올"],hint:"Thing + observation. Past tense before 모양이다."},
{type:"mc",q:"Which correctly pairs evidence + conclusion?",opts:["걸 보니 짐을 싸서 여행 모양이에요 (mixed up)","모양이에요 걸 보니 여행이에요 (wrong order)","짐을 싸는 걸 보니 여행을 가는 모양이에요 (packing = seems traveling)","여행 모양이에요 걸 보니 짐을 싸요 (reversed)"],ans:"짐을 싸는 걸 보니 여행을 가는 모양이에요 (packing = seems traveling)",hint:"Visible evidence leads to an inference. Packing bags suggests a trip."},
{type:"drag_fill",s:"뉴스에 자주 나오{1} 걸 보니 {2}한 사건인 {3}이에요.\n(Judging by frequent news coverage, it seems like an important incident.)",blanks:{"1":"는","2":"중요","3":"모양"},pool:["는","중요","모양","은","심각","편"],hint:"Present tense modifier. Importance. Appearance/seeming."},
{type:"drag_fill",s:"{1}에 따르면 {2}가 증가한 것으로 나타났{3} {4}을 입{5} 걸 보니 날씨가 추{6} 모양입니다.\n(According to statistics, it was found that sales increased. Judging by wearing coats, it seems the weather is cold.)",blanks:{"1":"통계","2":"매출","3":"으며","4":"코트","5":"는","6":"운"},pool:["통계","매출","으며","코트","는","운","보도","사건","고","우산","은","더운"],hint:"Data. Sales. Written 'and'. Outerwear. Present modifier. Cold adjective form."},
{type:"mc",q:"기사에 의하면 실업률이 높아진 것으로 나타났습니다.\n걸 보니 경제가 어려운 모양이에요.\nHow many U23 patterns?",opts:["One: 모양이다 only","Two: 에 의하면 + 나타났다","Three: 걸 보니 + 모양이다 + 나타났다","Four: 에 의하면, 것으로 나타났다, 걸 보니, 모양이다"],ans:"Four: 에 의하면, 것으로 나타났다, 걸 보니, 모양이다",hint:"Four inference-evidence patterns: citation, finding, observation-based judgment, appearance."},
{type:"drag_fill",s:"아시다시피 {1}이 심각하{2} {3}도 줄어든 것으로 {4}.\n(As you know, pollution is serious, and the population also seems to have decreased.)",blanks:{"1":"오염","2":"며","3":"인구","4":"보인다"},pool:["오염","며","인구","보인다","피해","고","매출","나타났다"],hint:"Contamination. Written 'and'. People count. Appears that (news cliche)."},

{type:"mc",q:"밖에 비가 오는 모양이에요.\n밖에 means?\n(It seems to be raining outside.)",opts:["밖에 = outside ","밖에 = only","밖에 = inside","밖에 = above"],ans:"밖에 = outside ",hint:"spatial vocabulary."},
{type:"drag_fill",s:"불{1} 꺼진 걸 보니 집에 없{2} 모양이에요. 차{3} 없{2} 걸 보니 나간 모양이에요.\n(Seeing lights are off, seems nobody's home. Seeing no car, seems they went out.)",blanks:{"1":"이","2":"는","3":"가"},pool:["이","는","가","을","은","의","에","를"],hint:"Subject. Present (seems). Subject."},
{type:"mc",q:"모양이다 vs 것 같다 :\nBoth mean 'it seems'. Difference?\n(Two inference patterns.)",opts:["Same meaning","모양이다: based on evidence you see; 것 같다: general opinion or guess","모양이다 is weaker","것 같다 requires evidence"],ans:"모양이다: based on evidence you see; 것 같다: general opinion or guess",hint:"모양 = appearance/shape. Based on what you observe."},
{type:"drag_fill",s:"표정{1} 보니까 화{2} 모양이에요. 맛있{3} 먹{4} 걸 보니 배고팠{2} 봐요.\n(Seeing the expression, seems angry. Seeing eating deliciously, seems was hungry.)",blanks:{"1":"을","2":"난","3":"게","4":"는"},pool:["을","난","게","는","이","는","어","의"],hint:"Object. Seems (angry). Adverbial. Present modifier."},
{type:"drag_fill",s:"모양이다: evidence-based {1}.\n걸 보니: {2} from observation.\n것 같다: general {3} .\n나 보다: {4} inference .\n(Four Korean inference patterns.)",blanks:{"1":"inference","2":"deduction","3":"guess","4":"mild"},pool:["inference","deduction","guess","mild","strong","certainty","opinion","fact"],hint:"모양=visual evidence. 걸 보니=from seeing. 것 같다=think. 나 보다=seems like."},
{type:"drag_fill",s:"요즘 바쁜 모양{1}에요. 연락{2} 안 하{3} 걸 보니 화{4} 모양이에요.\n(Seems busy these days. Judging by no contact, seems angry.)",blanks:{"1":"이","2":"을","3":"는","4":"난"},pool:["이","을","는","난","가","이","어","은"],hint:"Seems. Object. Present modifier. Seems (angry)."},
{type:"mc",q:"걸 보니(까) literally means?\n(Breaking down the inference pattern.)",opts:["Despite seeing","Because I heard","Seeing the fact that... (걸 = 것을, 보니 = since I see)","Without noticing"],ans:"Seeing the fact that... (걸 = 것을, 보니 = since I see)",hint:"Contracted object nominalizer + upon-seeing connector: judging by the fact that..."},
]},

// ── L7: 경험을 전해요 (Sharing Experiences) ──
{id:"kou23l7",title:"경험을 전해요",icon:"💬",xp:20,board:true,steps:[
{type:"intro",title:"Sharing Firsthand Experience",desc:"-더라(고요) / -던데(요)\n→ Reporting what YOU experienced or noticed.\n\nKorean has special endings for sharing\npersonal observations with others.",goals:["Use -더라(고요) for firsthand past experience","Use -던데(요) for sharing observations","Distinguish personal experience from hearsay"]},
{type:"teach",kind:"grammar",nl:"-더라(고요)",en:"I saw/experienced that (firsthand report)",pos:"part",gender:null,funFact:"Korean particles attach after nouns to mark their role. No equivalent in English.",phonetic:"deo-ra-go-yo",example:"A: 한국 여행 어땠어요? B: 한국 음식이 정말 맛있더라고요. A: 어떤 음식을 드셨어요? B: 삼겹살이랑 떡볶이를 먹었는데 다 좋더라고요. A: 매운 건 괜찮았어요? B: 처음에는 힘들었는데 먹다 보니 괜찮더라고요. A: 사람들은 친절했어요? B: 네, 길을 물어봤는데 정말 친절하더라고요. A: 또 가고 싶으세요? B: 물론이요. 볼 것도 정말 많더라고요.",exampleEn:"A: How was your trip to Korea? B: Korean food was really delicious, I found. A: What food did you try? B: I had samgyeopsal and tteokbokki and they were all great. A: Was the spicy food okay? B: At first it was tough, but as I kept eating it was fine, I found. A: Were the people friendly? B: Yes, I asked for directions and they were really kind, I found. A: Do you want to go again? B: Of course. There was so much to see, I found.",note:"Reports YOUR OWN past experience.\nYou personally saw, felt, or experienced it.\n\n-더라고요 (polite)\n-더라 (casual)\n\nCannot use for things you didn't experience.\nWrong: 지구가 둥글더라고요.\nRight: 한국이 정말 춥더라고요."},
{type:"teach",kind:"grammar",nl:"-던데(요)",en:"I noticed/found that (sharing observation)",pos:"adv",gender:null,funFact:"Korean has two negation systems: pre-verb 안 and post-verb -지 않다. Both are used daily.",phonetic:"deon-de-yo",example:"A: 점심 어디서 먹을까요? B: 새로 생긴 식당 가 봤는데, 분위기가 좋던데요. A: 음식은 어때요? B: 가격도 괜찮던데요, 한번 가 보실래요? A: 좋아요, 예약해야 해요? B: 평일에는 자리가 있던데요, 그냥 가도 될 것 같아요. A: 메뉴가 다양해요? B: 네, 한식이랑 양식 다 있던데요. A: 주차는 편해요? B: 건물 지하에 주차장이 있던데요, 넓어서 편했어요.",exampleEn:"A: Where shall we eat lunch? B: I tried the new restaurant, and the atmosphere was nice, I noticed. A: How is the food? B: The prices were reasonable too, want to try it? A: Sure, do we need a reservation? B: On weekdays there were seats available, I think we can just go. A: Is the menu varied? B: Yes, they had both Korean and Western food, I noticed. A: Is parking easy? B: There was a parking lot in the basement, I noticed it was spacious and convenient.",note:"Shares a personal observation, often to:\n1. Recommend something\n2. Add context to a conversation\n3. Gently disagree\n\n-던데요 (polite)\n-던데 (casual)"},
{type:"tip",title:"-더라 vs -던데",text:"Both report personal experience, but differ:\n\n-더라(고요): neutral report of experience\n 맛있더라고요 (it was delicious, I found)\n Just sharing what happened to you.\n\n-던데(요): observation + implication\n 맛있던데요 (it was delicious, you know)\n Often implies a recommendation or context.\n\nA: 그 카페 어때요?\nB1: 커피가 맛있더라고요. (just reporting)\nB2: 커피가 맛있던데요. (recommending it)",deepDive:"Tense forms with -더라:\n\nPresent experience: V-더라고요\n 비가 오더라고요 (it was raining, I saw)\n\nPast observation: V-았/었더라고요\n 이미 갔더라고요 (they had already gone)\n\n-던데 forms:\nV-던데요 (past/ongoing observation)\n 공부하던데요 (they were studying)\n\nV-았/었던데요 (completed observation)\n 이미 끝났던데요 (it had already ended)\n\nKey constraint: ONLY for what YOU experienced.\nFor hearsay (what others told you), use -다더라."},
{type:"mc",q:"한국 음식이 정말 맛있더라고요.\nThis means the speaker:",opts:["Personally experienced that Korean food was delicious","Heard from someone that Korean food is delicious","Assumes Korean food is delicious","Read that Korean food is delicious"],ans:"Personally experienced that Korean food was delicious",hint:"-더라고요 = firsthand experience report."},
{type:"fb",s:"그 영화 재미있{1}.\n(That movie was fun, I found.) (casual)",a:"더라",opts:["더라","던데","다더라","다면서"],hint:"Firsthand experience, casual form."},
{type:"mc",q:"A: 새로 생긴 식당 어때요?\nB: 분위기가 좋던데요.\nWhat is B doing?",opts:["Reporting hearsay","Sharing a personal observation (recommending)","Stating a general fact","Asking a question"],ans:"Sharing a personal observation (recommending)",hint:"-던데요 shares observation with an implication (recommendation)."},
{type:"fb",s:"어제 가 봤는데 사람이 많{1}요.\n(I went yesterday and there were a lot of people, I noticed.)",a:"던데",opts:["던데","더라고","다더라","다면서"],hint:"Sharing observation with implication."},
{type:"mc",q:"Which CAN'T use -더라고요?",opts:["음식이 맛있더라고요 (food was delicious)","한국이 춥더라고요 (Korea was cold)","지구가 둥글더라고요 (the earth is round)","길이 막히더라고요 (roads were jammed)"],ans:"지구가 둥글더라고요 (the earth is round)",hint:"-더라 is for PERSONAL experience, not general facts."},
{type:"drag_fill",s:"한국어 공부가 생각보다 어렵{1} 포기하면 안 되{2}\n(Korean study was harder than I thought, but we shouldn't give up, you know.)",blanks:{"1":"던데요.","2":"죠?"},pool:["던데요.","죠?","더라고요.","요.","던데.","지?"],hint:"Sharing observation. Tag question."},
{type:"drag_fill",s:"한국에 가 봤는데 정말 좋{1} 특히 음식이 맛있{2}\n(I went to Korea and it was really good. Especially the food was delicious, I found.)",blanks:{"1":"던데요.","2":"더라고요."},pool:["던데요.","더라고요.","다더라.","다면서요?"],hint:"Observation + implication first. Then neutral experience report."},
{type:"mc",q:"뉴스에서 봤는데 실업률이 높아지고 있던데요.\n걸 보니 경제가 어려운 모양이에요.\nU23 patterns used:",opts:["Two: 걸 보니 + 나타났다","One: -던데요 only","Three: -더라 + -던데 + 모양이다","Two: -던데요 (observation) + 걸 보니 + 모양이다 (inference)"],ans:"Two: -던데요 (observation) + 걸 보니 + 모양이다 (inference)",hint:"Two inference patterns: sharing a past observation vs. drawing a conclusion from evidence."},
{type:"drag_fill",s:"아시{1} 한국 뉴스는 {2}에 의해 보도되{3} 그 기사 읽어 봤는데 내용이 좋{4}\n(As you know, Korean news is reported by journalists. I read that article and the content was good, I found.)",blanks:{"1":"다시피","2":"기자","3":"며","4":"더라고요."},pool:["다시피","기자","며","더라고요.","보니","전문가","고","던데요."],hint:"As you know. Reporter. Written 'and'. Firsthand experience report."},
{type:"drag_fill",s:"그 {1}에 따르면 {2}로 인해 {3}가 늘어난 것으로 나타났{4} 저도 직접 가 봤는데 사람이 정말 많{5}\n(According to that article, it was found tourism increased due to the drama. I also went personally and there were many people, I noticed.)",blanks:{"1":"기사","2":"드라마","3":"관광객","4":"는데","5":"던데요."},pool:["기사","드라마","관광객","는데","던데요.","보도","영화","매출","으며","더라고요."],hint:"Article. TV series. Tourists. Connecting. Observation + implication."},

{type:"mc",q:"어제 가 봤는데 정말 맛있더라고요.\n-아/어 보다 means?\n(I went yesterday and it was really delicious.)",opts:["-아/어 보다 = to try doing ","보다 = to see","보다 = to compare","보다 = to send"],ans:"-아/어 보다 = to try doing ",hint:"experience auxiliary verb."},
{type:"drag_fill",s:"직접 먹어 봤{1}데 맛{2} 없더라{3}요. 생각보{4} 별로였어요.\n(I tried eating it myself and it wasn't tasty. It was worse than expected.)",blanks:{"1":"는","2":"이","3":"고","4":"다"},pool:["는","이","고","다","은","가","어","는"],hint:"Past observation. Subject. Firsthand report. Than-expected."},
{type:"mc",q:"-더라고요 vs -던데요:\nBoth share firsthand experience.\n더라고요 = I found that X.\n던데요 = I noticed X, and... (implies follow-up).\nWhich invites the listener to respond?\n(Two experience-sharing patterns.)",opts:["더라고요 invites response","던데요 invites response; 더라고요 is a statement","Both invite response equally","Neither invites response"],ans:"던데요 invites response; 더라고요 is a statement",hint:"One observation ending invites response; the other is a closed statement."},
{type:"drag_fill",s:"한국 음식{1} 정말 맵더라{2}요. 근데 맛있{3}데요, 한번 드셔 보세요.\n(Korean food was really spicy [I experienced]. But it was tasty, try it.)",blanks:{"1":"이","2":"고","3":"던"},pool:["이","고","던","은","어","는","가","다"],hint:"Subject. Firsthand (I found). Observation (and...)."},
{type:"drag_fill",s:"-더라고요: I {1} found that.\n-던데요: I noticed, {2}...\n-더라: casual {3} form.\n(Experience-sharing patterns.)",blanks:{"1":"personally","2":"and","3":"firsthand"},pool:["personally","and","firsthand","supposedly","but","hearsay","formally","or"],hint:"더라고요=my finding. 던데요=my notice, implicit follow-up. 더라=casual ver."},
{type:"drag_fill",s:"서울{1} 가 봤{2}데 사람{3} 정말 많더라{4}요.\n(I went to Seoul and there were really a lot of people.)",blanks:{"1":"에","2":"는","3":"이","4":"고"},pool:["에","는","이","고","을","은","가","어"],hint:"Location. Past observation. Subject. Firsthand report."},
]},

// ── L8: 들은 이야기 (What I Heard — Hearsay) ──
{id:"kou23l8",title:"들은 이야기",icon:"👂",xp:20,board:true,steps:[
{type:"intro",title:"Hearsay Reporting",desc:"-다더라 / -다면서(요)?\n→ Reporting what OTHERS told you.\n\n-다더라: I heard that (passing on info)\n-다면서?: Is it true that? (confirming hearsay)",goals:["Use -다더라 for reporting hearsay","Use -다면서? for confirming hearsay","Distinguish hearsay (-다더라) from firsthand (-더라)"]},
{type:"teach",kind:"grammar",nl:"-(ㄴ/는)다더라",en:"I heard that / apparently (hearsay)",pos:"part",gender:null,funFact:"Korean particles attach after nouns to mark their role. No equivalent in English.",phonetic:"da-deo-ra",example:"A: 이번 주말에 뭐 할 거야? B: 새로 생긴 카페에 가려고. 맛있다더라. A: 누가 그랬어? B: 직장 동료가 갔다 왔는데 분위기도 좋다더라. A: 나도 같이 가도 돼? B: 그럼, 토요일에 가자. 디저트가 유명하다더라. A: 가격은 어때? B: 좀 비싸다더라. 근데 양이 많다고 했어. A: 주차는 돼? B: 근처에 공영주차장이 있다더라.",exampleEn:"A: What are you doing this weekend? B: I am going to a new cafe. I heard it is good. A: Who said that? B: A coworker went and said the atmosphere was nice too. A: Can I come too? B: Sure, let us go Saturday. I heard their desserts are famous. A: How are the prices? B: I heard they are a bit expensive. But the portions are big, they said. A: Is there parking? B: I heard there is a public parking lot nearby.",note:"Passing on what SOMEONE ELSE said.\nYou did NOT experience it yourself.\n\nAction: V-ㄴ/는다더라\n 간다더라 (I heard they're going)\nDescription: A-다더라\n 좋다더라 (I heard it's good)\nNoun: N-(이)라더라\n 학생이라더라 (I heard they're a student)"},
{type:"teach",kind:"grammar",nl:"-(ㄴ/는)다면서(요)?",en:"I heard that...? Is it true?",pos:"part",gender:null,funFact:"Korean particles attach after nouns to mark their role. No equivalent in English.",phonetic:"da-myeon-seo-yo",example:"A: 한국에 간다면서요? 정말이에요? B: 네, 다음 달에 출장이에요. A: 좋겠다. 서울이라면서요? B: 네, 2주 정도 있을 예정이에요. A: 한국어 공부한다면서요? B: 네, 이번 기회에 실력을 시험해 보려고요. A: 혼자 간다면서요? B: 아니요, 팀장님이랑 같이 가요. A: 맛있는 거 많이 먹는다면서요? B: 그럼요. 현지 음식을 꼭 먹어 볼 거예요.",exampleEn:"A: I heard you're going to Korea? Really? B: Yes, I have a business trip next month. A: Lucky you. I heard it's Seoul? B: Yes, I plan to stay about 2 weeks. A: I heard you're studying Korean? B: Yes, I want to test my skills with this opportunity. A: I heard you're going alone? B: No, I am going with the team leader. A: I heard you'll eat a lot of good food? B: Of course. I will definitely try the local food.",note:"Confirming hearsay with the person involved.\nAsking: 'Is what I heard true?'\n\nAction: V-ㄴ/는다면서(요)?\nDescription: A-다면서(요)?\nNoun: N-(이)라면서(요)?"},
{type:"tip",title:"Experience vs Hearsay",text:"Korean clearly distinguishes:\n\n-더라(고요): I experienced it myself\n 맛있더라고요 (it was delicious = I tasted it)\n\n-다더라: someone told me\n 맛있다더라 (I heard it's delicious)\n\n-다면서?: confirming what I heard\n 맛있다면서요? (I heard it's delicious, right?)\n\nMixing these up is a real error in Korean.\nSaying -더라 about something you only heard\nwould be considered dishonest.",deepDive:"The hearsay chain:\n\nOriginal: 이 식당이 맛있어요. (This is delicious.)\n\nReporting to friend:\n 거기 맛있다더라. (I heard it's good.)\n\nConfirming with original speaker:\n 거기 맛있다면서요? (I heard it's good, right?)\n\nCombining in news context:\n 전문가에 따르면 경제가 회복되는 것으로 나타났다.\n (formal: According to experts, it was found...)\n\n 경제가 회복된다더라.\n (casual: I heard the economy is recovering.)\n\nSame info, different register and evidence level."},
{type:"mc",q:"그 식당이 맛있다더라.\nThe speaker:",opts:["Heard from someone else that it's good","Personally experienced that it's good","Is guessing it might be good","Read in a news article that it's good"],ans:"Heard from someone else that it's good",hint:"-다더라 = hearsay. Someone told me."},
{type:"fb",s:"한국에 {1}다면서요? 정말이에요?\n(I heard you're going to Korea? Really?)",a:"간",opts:["간","가는","갔","갈"],hint:"Confirming hearsay about a plan. Action verb form."},
{type:"mc",q:"A: 맛있더라고요. (firsthand)\nB: 맛있다더라. (hearsay)\nWhat's the difference?",opts:["A is formal, B is casual","A tasted it personally, B only heard about it","A is present, B is past","No meaningful difference"],ans:"A tasted it personally, B only heard about it",hint:"-더라 = my experience. -다더라 = someone else told me."},
{type:"fb",s:"그 회사 연봉이 높{1}. 친구한테 들었어.\n(I heard that company's salary is high. Heard from a friend.)",a:"다더라",opts:["다더라","더라고","던데","다면서"],hint:"Hearsay (someone told me). Casual."},
{type:"mc",q:"취직했다면서요? 축하해요!\nWhat is the speaker doing?",opts:["Asking a general question","Reporting their own experience","Confirming hearsay: I heard you got a job, right?","Stating a news fact"],ans:"Confirming hearsay: I heard you got a job, right?",hint:"-다면서요? confirms something heard from others."},
{type:"drag_fill",s:"내일 {1}라더라. 우산 가져가{2}.\n(I heard it's rain tomorrow. Take an umbrella, right.)",blanks:{"1":"비","2":"야지"},pool:["비","야지","눈","죠","태풍","세요"],hint:"Precipitation. Casual suggestion."},
{type:"drag_fill",s:"그 {1}이 재미있{2} 직접 봤는데 정말 좋{3}\n(I heard that movie is fun. I watched it myself and it was really good.)",blanks:{"1":"영화","2":"다더라.","3":"더라고요."},pool:["영화","다더라.","더라고요.","드라마","던데요.","다면서요?"],hint:"Film. Hearsay. Firsthand experience."},
{type:"mc",q:"뉴스에서 경제가 회복된다더라.\n보도에 따르면 회복되고 있는 것으로 나타났습니다.\nSame info, different register:",opts:["Both are casual","First is formal, second is casual","Both are formal","First is casual hearsay, second is formal news writing"],ans:"First is casual hearsay, second is formal news writing",hint:"-다더라 is casual retelling. 것으로 나타났다 is news cliche."},
{type:"drag_fill",s:"저 사람이 {1}라더라. 그런데 직접 만나 보니 친절하{2}\n(I heard that person is an expert. But meeting them, they were kind.)",blanks:{"1":"전문가","2":"던데요."},pool:["전문가","던데요.","기자","더라고요.","경찰","다더라."],hint:"Specialist. Personal observation + implication."},
{type:"drag_fill",s:"{1}에 의하면 새 정책이 시행{2} 것으로 {3} 친구도 그렇{4} 정말{5}?\n(According to reports, the policy will be implemented. My friend said so too. Is it really true?)",blanks:{"1":"보도","2":"될","3":"알려졌습니다.","4":"다더라.","5":"다면서요"},pool:["보도","될","알려졌습니다.","다더라.","다면서요","통계","된","나타났습니다.","던데요.","더라고요"],hint:"News. Future. Was reported. Hearsay. Confirming hearsay."},

{type:"mc",q:"그 식당 맛있다더라.\n-다더라 is hearsay. What's the source?\n(I heard that restaurant is good.)",opts:["Someone else told the speaker (secondhand info)","Speaker's own experience","News article","Written report"],ans:"Someone else told the speaker (secondhand info)",hint:"다더라 = they said / I heard from someone."},
{type:"drag_fill",s:"내일 비 온{1}더라. 진짜? 누{2} 그랬어?\n(I heard it's going to rain. Really? Who said that?)",blanks:{"1":"다","2":"가"},pool:["다","가","는","이","어","를","에","의"],hint:"Hearsay. Subject (who?)."},
{type:"mc",q:"-다더라 (hearsay) vs -더라고요 (firsthand):\n그 영화 재미있다더라. (heard from someone)\n그 영화 재미있더라고요. (I watched it myself)\nCritical difference?\n(Two reporting patterns.)",opts:["Same meaning","다더라: secondhand (someone told me); 더라고요: firsthand (I experienced)","다더라 is more formal","더라고요 is secondhand"],ans:"다더라: secondhand (someone told me); 더라고요: firsthand (I experienced)",hint:"다 in front = reported. No 다 = personal experience."},
{type:"drag_fill",s:"한국어 시험 어렵{1}면서요? 네, 저{2} 어렵더라{3}요.\n(I heard the Korean exam is hard? Yes, I found it hard [from experience].)",blanks:{"1":"다","2":"도","3":"고"},pool:["다","도","고","는","가","어","이","에"],hint:"Confirming hearsay. Also/too. Firsthand report."},
{type:"drag_fill",s:"-다더라: {1} info, casual.\n-다면서(요): confirming {2}.\n-더라고요: {3} experience.\n-더라: casual {3} report.\n(Four reporting patterns.)",blanks:{"1":"secondhand","2":"hearsay","3":"firsthand"},pool:["secondhand","hearsay","firsthand","written","formal","thirdhand","guessed","opinion"],hint:"다더라=heard. 다면서=you heard? 더라고요=I saw. 더라=I saw (casual)."},
{type:"drag_fill",s:"요즘 그 드라마 재미있{1}면서요? 맞{2}요, 저{3} 봤{4}데 진짜 좋더라고요.\n(I hear that drama is fun? Right, I watched it and it was really good.)",blanks:{"1":"다","2":"아","3":"도","4":"는"},pool:["다","아","도","는","는","어","가","은"],hint:"Confirming hearsay. Correct. Also/too. Past observation."},
]},

// ── L9: 기사 구조 (Article Structure) ──
{id:"kou23l9",title:"기사 구조",icon:"🗞️",xp:20,board:true,steps:[
{type:"intro",title:"Korean Article Structure",desc:"기사 구조\n→ Putting it all together: reading a full Korean news article.\n\nHeadline → Lead → Body → Quote\nEach section uses specific grammar patterns.",goals:["Identify the four parts of a Korean news article","Match grammar patterns to article sections","Practice reading comprehension of news Korean"]},
{type:"tip",title:"기사 4단 구조 (4-Part Article)",text:"Every Korean news article follows this pattern:\n\n1. 제목 (headline): 2-8 words, no verb ending\n 서울 지하철 파업 결정\n\n2. 리드 (lead): one sentence summary\n 것으로 알려졌다 / 것으로 나타났다\n\n3. 본문 (body): details with formal connectors\n -(으)며, -(으)로 인해, -에 의해, -에 따라\n\n4. 인용 (quote): attributed speech\n -다고 밝혔다, -라고 전했다",deepDive:"Practice reading this structure:\n\nHeadline:\n 서울 미세먼지 비상 (Seoul Fine Dust Emergency)\n\nLead:\n 서울시 미세먼지가 위험 수준인 것으로 나타났다.\n\nBody:\n 환경부에 따르면 이번 미세먼지는 중국발 오염으로 인해\n 발생했으며, 시민들의 건강 피해가 우려된다.\n\nQuote:\n 환경부 관계자는 '외출을 자제해 달라'고 당부했다.\n\nNotice: EVERY sentence uses formal patterns.\nThis is the written register you've been learning."},
{type:"mc",q:"Korean news headline style is:",opts:["Short noun phrases, no verb ending","Full formal sentences","Casual spoken style","Question format"],ans:"Short noun phrases, no verb ending",hint:"Headlines drop verb endings for brevity."},
{type:"fb",s:"실업률이 증가한 것으로 {1}.\nThis sentence belongs in the:",a:"나타났다",opts:["나타났다","알려졌다","보인다","밝혔다"],hint:"Research/survey result in a lead sentence."},
{type:"mc",q:"관계자는 '협상을 계속하겠다'고 밝혔다.\nThis is which part of a news article?",opts:["Headline (제목)","Quote (인용) .  attributed speech","Lead (리드)","Body (본문)"],ans:"Quote (인용) .  attributed speech",hint:"-다고 밝혔다 = stated that. Attributed speech."},
{type:"teach",kind:"noun",nl:"미세먼지",en:"fine dust / particulate matter",pos:"noun",gender:null,funFact:"Sino-Korean compound: 미(tiny/微) + 세(small/細) + 먼지(dust)",phonetic:"mi-se-meon-ji",example:"미세먼지로 인해 외출이 어렵습니다.\n(Going out is difficult due to fine dust.)",exampleEn:"Going out is difficult due to fine dust.",note:"COMPOUND: 미(tiny/微) + 세(small/細) + 먼지(dust).\nTiny-small-dust: airborne particles.\nA major concern in Korean daily life.\n미세먼지 농도 = fine dust concentration."},
{type:"teach",kind:"noun",nl:"환경",en:"environment",pos:"noun",gender:null,funFact:"From hanja: 環 (ring) + 境 (border). Ring border = environment.",phonetic:"hwan-gyeong",example:"환경 보호가 중요합니다.\n(Environmental protection is important.)",exampleEn:"Environmental protection is important.",note:"COMPOUND: 환(surround/環) + 경(boundary/境).\nSurrounding-boundary: the world around us.\n환경부 = Ministry of Environment."},
{type:"drag_fill",s:"{1}에 따르면 {2}로 인해 {3} 피해가 발생한 것으로 {4}.\n(According to the Ministry of Environment, health damage occurred due to fine dust, it was found.)",blanks:{"1":"환경부","2":"미세먼지","3":"건강","4":"나타났다"},pool:["환경부","미세먼지","건강","나타났다","전문가","태풍","경제","알려졌다"],hint:"Government body. Tiny particles. Wellbeing. Found that."},
{type:"mc",q:"A news body paragraph would use:",opts:["Noun-stop headline style","것으로 나타났다 (lead cliche)","-(으)며, -(으)로 인해, -에 의해, -에 따라","Casual -더라고요"],ans:"-(으)며, -(으)로 인해, -에 의해, -에 따라",hint:"Body paragraphs use formal connectors for detail."},
{type:"drag_fill",s:"미세먼지{1} 인해 건강 {2}가 우려되{3} {4}부에 {5} 대책이 필요한 것으로 {6}.\n(Health damage is a concern due to fine dust, and according to the Ministry of Environment, measures are needed, it appears.)",blanks:{"1":"로","2":"피해","3":"며","4":"환경","5":"따르면","6":"보인다"},pool:["로","피해","며","환경","따르면","보인다","에","사건","고","전문가","의하면","나타났다"],hint:"Cause particle. Suffer-harm. Written 'and'. Ministry. Citation. Appears."},
{type:"drag_fill",s:"아시{1} {2} 문제는 심각합니{3} {4}에 의해 다양한 {5}가 추진되고 있습니다.\n(As you know, the environment problem is serious. Various measures are being pursued by the government.)",blanks:{"1":"다시피","2":"환경","3":"다.","4":"정부","5":"대책"},pool:["다시피","환경","다.","정부","대책","보니","경제","요.","전문가","정책"],hint:"As you know. Surroundings. Period. Government. Countermeasures."},
{type:"match",pairs:[{nl:"제목",en:"headline"},{nl:"리드",en:"lead sentence"},{nl:"본문",en:"body paragraph"},{nl:"인용",en:"attributed quote"}]},
{type:"mc",q:"직접 가 봤는데 미세먼지가 심하던데요.\n보도에 따르면 위험 수준인 것으로 나타났습니다.\nFirst sentence is ___; second is ___.",opts:["Hearsay; personal experience","Both formal news","Both casual speech","Personal observation; formal news writing"],ans:"Personal observation; formal news writing",hint:"One pattern comes from seeing something yourself, the other from published data. Match the source."},
{type:"drag_fill",s:"{1}: 서울 미세먼지 {2}\n{3}: 미세먼지 농도가 위험 수준인 것으로 {4}\n{5}: 중국발 오염{6} 인해 발생했{7} 시민 건강이 우려된다.",blanks:{"1":"제목","2":"비상","3":"리드","4":"나타났다.","5":"본문","6":"으로","7":"으며"},pool:["제목","비상","리드","나타났다.","본문","으로","으며","인용","경고","본문","알려졌다.","리드","에","고"],hint:"Headline. Emergency. Lead. Found that. Body. Due to. Written 'and'."},

{type:"drag_fill",s:"기사{1} 따르면 올해 경제{2} 성장할 것으로 보인다. 전문가{3} 의해 분석되었다.\n(According to the article, economy appears set to grow this year. Analyzed by experts.)",blanks:{"1":"에","2":"가","3":"에"},pool:["에","가","에","의","를","이","는","에서"],hint:"According-to. Subject. Passive agent."},
{type:"mc",q:"A news article uses: 으로 인해, 에 의해, 에 따르면, 것으로 나타났다.\nWhich pattern would a CASUAL friend use instead of 으로 인해?\n(Formal news vs casual speech.)",opts:["때문에 ","에 의해","에 따르면","것으로 나타났다"],ans:"때문에 ",hint:"Which casual causal connector replaces the formal 으로 인해?"},
{type:"drag_fill",s:"Headline: short, {1} style.\nLead: who/what/when, uses {2}.\nBody: details, uses {3}.\nQuote: 다고 했다 or {4}.\n(Korean news structure.)",blanks:{"1":"noun-heavy","2":"것으로 나타났다","3":"에 따르면","4":"다면서"},pool:["noun-heavy","것으로 나타났다","에 따르면","다면서","verb-heavy","모양이다","때문에","더라고요"],hint:"Headlines omit verbs. Leads cite findings. Body cites sources. Quotes report speech."},
{type:"drag_fill",s:"제목{1} 보{2} 기사 내용{3} 예측할 수 있어요. 리드{1} 핵심 정보{4} 있어요.\n(You can predict article content by seeing the headline. The lead has core information.)",blanks:{"1":"을","2":"면","3":"을","4":"가"},pool:["을","면","을","가","이","는","에","의"],hint:"Object. conditional. Object. Subject."},

{type:"drag_fill",s:"제목{1} 짧{2} 명사형{3}로 쓴다. 리드{1} 핵심{4} 요약한다.\n(Headlines are written as short noun forms. Leads summarize the key points.)",blanks:{"1":"은","2":"은","3":"으","4":"을"},pool:["은","은","으","을","이","는","가","의"],hint:"Topic (x2). As (form). Object."},
{type:"mc",q:"Korean news headlines drop particles and verbs.\nFull: 정부가 새 정책을 발표했다.\nHeadline style?\n(How headlines abbreviate.)",opts:["정부가 새 정책을 발표했다 (same as full)","정부, 새 정책 발표 (no particles, noun-ending)","정부는 발표 (topic only)","새 정책 정부 (reversed)"],ans:"정부, 새 정책 발표 (no particles, noun-ending)",hint:"Headlines: drop 가/를/은, end with noun form."},
{type:"drag_fill",s:"인용문{1} 다고 했다 또{2} 다면서요 형태{3} 쓴다. 기사{4} 객관적{5}야 한다.\n(Quotes use the form 다고 했다 or 다면서요. Articles must be objective.)",blanks:{"1":"은","2":"는","3":"로","4":"는","5":"이어"},pool:["은","는","로","는","이어","이","를","가","의","에"],hint:"Topic. Or/also. As (form). Topic. Must-be."},
]},

// ── L10: 종합 평가 (Unit Assessment) ──
{id:"kou23l10",title:"종합 평가",icon:"📋",xp:25,board:true,steps:[
{type:"intro",title:"Unit 23 Assessment",desc:"U23 종합 평가\n→ All news and reporting patterns reviewed.\n\n11 patterns: 으로 인해, 에 의해, 에 따라,\n것으로 나타났다, 다시피, 모양이다, 걸 보니,\n더라, 던데, 다더라, 다면서",goals:["Demonstrate mastery of all U23 patterns","Choose correct formal register patterns","Distinguish experience from hearsay","Read and analyze news article structure"]},
{type:"mc",q:"폭우로 인해 도로가 침수되었습니다.\n으로 인해 is:",opts:["Formal 'due to' (external cause, written register)","Passive 'by' (agent marker)","'According to' (citation)","'It seems that' (inference)"],ans:"Formal 'due to' (external cause, written register)",hint:"This pattern marks an external event that caused something. Think: formal written register for causes."},
{type:"fb",s:"이 법은 국회{1} 의해 통과되었습니다.\n(This law was passed by the National Assembly.)",a:"에",opts:["에","로","가","를"],hint:"Passive agent marker particle before 의해."},
{type:"mc",q:"통계에 따르면 vs 상황에 따라.\nWhat's the difference?",opts:["Both mean the same thing","따르면 = according to (source); 따라 = depending on (variation)","따르면 is formal, 따라 is casual","따르면 is past, 따라 is present"],ans:"따르면 = according to (source); 따라 = depending on (variation)",hint:"Two faces of the same grammar."},
{type:"fb",s:"인구가 감소하고 있는 것으로 {1}.\n(It was found that population is decreasing.)",a:"나타났다",opts:["나타났다","알려졌다","보인다","밝혔다"],hint:"Survey/research result cliche."},
{type:"mc",q:"맛있더라고요 vs 맛있다더라.\nThe key difference:",opts:["Both mean someone told me","Both mean I tasted it","-더라고요 = I tasted it myself; -다더라 = someone told me","-더라고요 is formal, -다더라 is casual"],ans:"-더라고요 = I tasted it myself; -다더라 = someone told me",hint:"Firsthand vs hearsay. Critical distinction in Korean."},
{type:"drag_fill",s:"비가 올 {1}이에요. 하늘이 어두운 {2} 보니.\n(It seems it will rain. Judging by the dark sky.)",blanks:{"1":"모양","2":"걸"},pool:["모양","걸","편","것을"],hint:"Evidence-based seeming. Thing + observation."},
{type:"mc",q:"한국에 간다면서요?\nThe speaker is:",opts:["Citing a news source","Reporting firsthand experience","Making an inference","Confirming hearsay: 'I heard you're going, right?'"],ans:"Confirming hearsay: 'I heard you're going, right?'",hint:"-다면서요? = confirming something heard from others."},
{type:"drag_fill",s:"{1}다시피 이 문제는 심각합니{2} {3}에 의해 {4}가 진행 중입니다.\n(As you know, this problem is serious. Investigation is underway by experts.)",blanks:{"1":"아시","2":"다.","3":"전문가","4":"조사"},pool:["아시","다.","전문가","조사","보시","요.","경찰","발표"],hint:"Know + as. Formal period. Specialists. Inquiry."},
{type:"match",pairs:[{nl:"으로 인해",en:"due to (cause)"},{nl:"에 의해",en:"by (agent)"},{nl:"에 따르면",en:"according to"},{nl:"것으로 나타났다",en:"it was found that"}]},
{type:"drag_fill",s:"{1}에 따르면 {2}로 인해 {3}가 증가한 것으로 {4}{5} {6}에 의해 {7}가 진행되고 있습니다.\n(According to reports, it was found that damage increased due to the earthquake. Investigation is being conducted by the government.)",blanks:{"1":"보도","2":"지진","3":"피해","4":"나타났","5":"으며","6":"정부","7":"조사"},pool:["보도","지진","피해","나타났","으며","정부","조사","통계","태풍","사건","알려졌","고","경찰","발표"],hint:"Report. Earthquake. Damage. Found. Written 'and'. Government. Inquiry."},
{type:"mc",q:"직접 가 봤는데 좋던데요.\n보도에 따르면 인기가 높은 것으로 나타났습니다.\n친구도 좋다더라.\nThree different evidence levels:",opts:["Personal observation; formal news; hearsay","All the same level","News; personal; guess","Hearsay; news; personal"],ans:"Personal observation; formal news; hearsay",hint:"-던데 = I noticed. 나타났다 = data shows. -다더라 = I heard."},
{type:"drag_fill",s:"{1}로 인한 {2}가 심각하{3} {4}에 의한 {5}가 필요한 것으로 {6}.\n(Damage due to pollution is serious, and analysis by experts is needed, it appears.)",blanks:{"1":"오염","2":"피해","3":"며","4":"전문가","5":"분석","6":"보인다"},pool:["오염","피해","며","전문가","분석","보인다","미세먼지","사건","고","경찰","조사","나타났다"],hint:"Contamination. Damage. Written 'and'. Specialists. Examination. Appears."},
{type:"drag_fill",s:"그 {1}이 재미있{2} 직접 봤는데 정말 좋{3} 간{4}?\n(I heard that movie is fun. I watched it and it was really good. Are you going, I heard?)",blanks:{"1":"영화","2":"다더라.","3":"더라고요.","4":"다면서요"},pool:["영화","다더라.","더라고요.","다면서요","드라마","던데요.","더라.","다면서"],hint:"Film. Hearsay. Firsthand. Confirming hearsay."},
{type:"mc",q:"다음 중 U23에서 배운 패턴이 아닌 것은?",opts:["-(으)로 인해 (due to)","-(으)ㄴ/는 반면에 (whereas .  U22)","것으로 나타났다 (it was found that)","-(ㄴ/는)다더라 (I heard that)"],ans:"-(으)ㄴ/는 반면에 (whereas .  U22)",hint:"Structured contrast belongs to a previous unit. This unit focuses on news language."},
{type:"drag_fill",s:"{1}다시피 {2} 문제가 심각하{3} {4}에 따르면 {5}로 인한 건강 {6}가 증가한 것으로 {7}.\n(As you know, the environment problem is serious. According to experts, health damage from fine dust has increased, it was found.)",blanks:{"1":"아시","2":"환경","3":"며","4":"전문가","5":"미세먼지","6":"피해","7":"나타났습니다"},pool:["아시","환경","며","전문가","미세먼지","피해","나타났습니다","보시","경제","고","보도","태풍","사건","알려졌습니다"],hint:"Know-as. Environment. Written 'and'. Experts. Fine dust. Damage. Found."},

{type:"drag_fill",s:"조사{1} 따르면 젊은이{2} 70%{3} 온라인 뉴스{4} 본다고 한다.\n(According to survey, 70% of young people reportedly read online news.)",blanks:{"1":"에","2":"의","3":"가","4":"를"},pool:["에","의","가","를","이","는","을","에서"],hint:"According-to. Possessive. Subject. Object."},
{type:"mc",q:"Multi-pattern: 경기 침체로 인해 실업률이 높아진 것으로 나타났다.\nHow many patterns?\n(Due to recession, unemployment was shown to have risen.)",opts:["3 patterns","1 pattern","2: 으로 인해 (formal cause) + 것으로 나타났다 (news cliche)","0 patterns"],ans:"2: 으로 인해 (formal cause) + 것으로 나타났다 (news cliche)",hint:"Formal cause + news finding formula."},
{type:"drag_fill",s:"Firsthand: -더라고요, {1}.\nSecondhand: -다더라, {2}.\nFormal citation: -에 따르면, {3}.\n(Sorting by evidence source.)",blanks:{"1":"-던데요","2":"-다면서요","3":"-에 의하면"},pool:["-던데요","-다면서요","-에 의하면","-것 같다","-나 보다","-모양이다"],hint:"Personal experience. Hearsay confirmation. Formal report."},

{type:"drag_fill",s:"보도{1} 따르면 사고{2} 원인{3} 과속{4} 인한 것으로 나타났다.\n(According to reports, the accident cause was shown to be due to speeding.)",blanks:{"1":"에","2":"의","3":"이","4":"으로"},pool:["에","의","이","으로","를","가","는","에서"],hint:"According-to. Possessive. Subject. Formal cause."},
{type:"mc",q:"Complete news sentence: ___에 따르면 청소년의 스마트폰 사용이 증가한 것으로 ___.\nFill both blanks.\n(According to ___, teen smartphone use was shown to have increased.)",opts:["전문가 + 모양이다","뉴스 + 보인다","기사 + 알려졌다","조사 + 나타났다 (survey + was revealed)"],ans:"조사 + 나타났다 (survey + was revealed)",hint:"Survey data + revealed finding = most natural news pairing."},
]},

]};

export default UNIT_23;
